@import "tailwindcss";

:root {
  --background: #fffbeb;
  --foreground: #451a03;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
}

@media (prefers-color-scheme: dark) {
  :root {
    --background: #1c1210;
    --foreground: #fef3c7;
  }
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue",
    Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
}

/* ─── Notification pulse highlight (amber glow, 3 cycles) ───── */
@keyframes pulse-highlight {
  0%,
  100% {
    box-shadow: 0 0 0 0 transparent;
    background-color: transparent;
  }
  50% {
    box-shadow: 0 0 16px 4px rgba(251, 191, 36, 0.35);
    background-color: rgba(253, 230, 138, 0.25);
  }
}

.animate-pulse-highlight {
  animation: pulse-highlight 0.66s ease-in-out 3;
}

/* ─── Completed orders section (greyed out, reduced emphasis) ───── */
.completed-orders-section {
  opacity: 0.55;
  filter: saturate(0.3);
  transition: opacity 0.3s ease, filter 0.3s ease;
}

.completed-orders-section:hover {
  opacity: 0.75;
  filter: saturate(0.5);
}

arguments.newText:
.completed-orders-section:hover {
  opacity: 0.75;
  filter: saturate(0.5);
}

/* ─── Admin card staggered enter animation ───── */
@keyframes adminCardEnter {
  from {
    opacity: 0;
    transform: translateY(12px) scale(0.97);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

